<div class="table-responsive data-shell"><table class="table align-middle"><thead><tr><th>Data</th><th>Requisitante</th><th>Equipa</th><th>Artigo</th><th>Armazém</th><th>Qtd</th><th>Entregue</th><th>Estado</th><th>Valor</th><th>Ações</th></tr></thead><tbody><?php foreach($rows as $r): $remaining=max(0,(float)$r['quantity']-(float)($r['delivered_quantity']??0)); ?><tr><td><?= htmlspecialchars(substr($r['created_at'],0,10)) ?></td><td><?= htmlspecialchars($r['requester']) ?></td><td><?= htmlspecialchars($r['team']) ?></td><td><?= htmlspecialchars($r['item']) ?></td><td><?= htmlspecialchars($r['warehouse'] ?? '-') ?></td><td><?= htmlspecialchars($r['quantity']) ?></td><td><strong><?= htmlspecialchars($r['delivered_quantity'] ?? 0) ?></strong><small class="text-muted"> / faltam <?= $remaining ?></small></td><td><span class="badge status-badge status-<?= strtolower($r['status']) ?>"><?= htmlspecialchars($r['status']) ?></span></td><td>€ <?= number_format((float)$r['request_value'],2,',','.') ?></td><td><div class="actions-stack"><a class="btn btn-sm btn-outline-success" href="<?= \App\Core\Url::page('request_action') ?>&id=<?= $r['id'] ?>&do=approve">Aprovar</a><form method="post" action="<?= \App\Core\Url::page('request_action') ?>&id=<?= $r['id'] ?>&do=deliver" class="deliver-form"><input class="form-control form-control-sm" name="deliver_quantity" type="number" min="0.01" max="<?= $remaining ?>" step="0.01" placeholder="Qtd" <?= $remaining<=0?'disabled':'' ?>><button class="btn btn-sm btn-outline-primary" <?= $remaining<=0?'disabled':'' ?>>Entregar</button></form><a class="btn btn-sm btn-outline-secondary" href="<?= \App\Core\Url::page('requests') ?>&edit=<?= $r['id'] ?>">Editar</a><a class="btn btn-sm btn-outline-danger" href="<?= \App\Core\Url::page('request_action') ?>&id=<?= $r['id'] ?>&do=cancel">Cancelar</a></div></td></tr><?php endforeach; ?></tbody></table></div>
